// Root layout — providers, theme, toast. NO navigation logic here.
import 'react-native-url-polyfill/auto';
import { useEffect } from 'react';
import { GestureHandlerRootView } from 'react-native-gesture-handler';
import { StyleSheet, View, ActivityIndicator } from 'react-native';
import { Slot } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
import { Provider as PaperProvider, MD3LightTheme, MD3DarkTheme } from 'react-native-paper';
import Toast from 'react-native-toast-message';
import { useColorScheme } from '@/hooks/use-color-scheme';
import { useAuthStore } from '@/store/authStore';
import { initializeSchema } from '@/lib/database';
import Colors from '@/constants/Colors';

const paperLightTheme = {
  ...MD3LightTheme,
  colors: {
    ...MD3LightTheme.colors,
    primary: Colors.light.primary,
    secondary: Colors.light.accent,
    background: Colors.light.background,
    surface: Colors.light.surface,
    error: Colors.light.error,
    onPrimary: Colors.light.textOnPrimary,
    onBackground: Colors.light.text,
    onSurface: Colors.light.text,
  },
};

const paperDarkTheme = {
  ...MD3DarkTheme,
  colors: {
    ...MD3DarkTheme.colors,
    primary: Colors.dark.primary,
    secondary: Colors.dark.accent,
    background: Colors.dark.background,
    surface: Colors.dark.surface,
    error: Colors.dark.error,
    onPrimary: Colors.dark.textOnPrimary,
    onBackground: Colors.dark.text,
    onSurface: Colors.dark.text,
  },
};

export default function RootLayout() {
  const colorScheme = useColorScheme();
  const { isLoading, restoreSession } = useAuthStore();

  // 1. Initialise local SQLite on first launch
  useEffect(() => {
    try { initializeSchema(); } catch (e) { console.error('[DB]', e); }
  }, []);

  // 2. Restore Supabase session (with 5-second timeout inside the store)
  useEffect(() => {
    restoreSession();
  }, []);

  const theme = colorScheme === 'dark' ? paperDarkTheme : paperLightTheme;

  // Show a blank loading screen while session is being restored.
  // The Slot renders NOTHING until isLoading is false, so there is
  // no risk of navigating before the navigator is mounted.
  if (isLoading) {
    return (
      <GestureHandlerRootView style={styles.container}>
        <PaperProvider theme={theme}>
          <View style={[styles.container, { backgroundColor: Colors.light.primary }]}>
            <ActivityIndicator color={Colors.light.accent} size="large" />
          </View>
          <StatusBar style="light" />
        </PaperProvider>
      </GestureHandlerRootView>
    );
  }

  return (
    <GestureHandlerRootView style={styles.container}>
      <PaperProvider theme={theme}>
        <Slot />
        <StatusBar style={colorScheme === 'dark' ? 'light' : 'dark'} />
        <Toast />
      </PaperProvider>
    </GestureHandlerRootView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
});

// OfflineBanner — animated yellow banner shown when device has no internet connection
import { useEffect, useRef } from 'react';
import { Animated, StyleSheet, Text, View } from 'react-native';
import { useNetworkStatus } from '@/hooks/useNetworkStatus';
import Colors from '@/constants/Colors';
import { useColorScheme } from '@/hooks/use-color-scheme';

const BANNER_HEIGHT = 36;

export function OfflineBanner() {
  const { isOnline } = useNetworkStatus();
  const colorScheme = useColorScheme();
  const colors = Colors[colorScheme ?? 'light'];
  const translateY = useRef(new Animated.Value(-BANNER_HEIGHT)).current;

  useEffect(() => {
    Animated.timing(translateY, {
      toValue: isOnline ? -BANNER_HEIGHT : 0,
      duration: 300,
      useNativeDriver: true,
    }).start();
  }, [isOnline]);

  return (
    <Animated.View
      style={[
        styles.banner,
        {
          backgroundColor: colors.warning,
          transform: [{ translateY }],
        },
      ]}
    >
      <Text style={styles.text}>
        ⚠️  Offline Mode — Changes will sync when connected
      </Text>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  banner: {
    height: BANNER_HEIGHT,
    width: '100%',
    alignItems: 'center',
    justifyContent: 'center',
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    zIndex: 999,
  },
  text: {
    color: '#000000',
    fontSize: 12,
    fontWeight: '600',
    textAlign: 'center',
  },
});

import React, { useRef, useState } from 'react';
import { Modal, StyleSheet, TouchableOpacity, View, ActivityIndicator } from 'react-native';
import { Text } from 'react-native-paper';
import { MaterialCommunityIcons } from '@expo/vector-icons';
import SignatureCanvas, { SignatureViewRef } from 'react-native-signature-canvas';
import Toast from 'react-native-toast-message';

const NAVY = '#0E2141', ORANGE = '#EA6C00', WHITE = '#FFFFFF', SUCCESS = '#15803D';

interface Props {
  visible: boolean;
  onClose: () => void;
  onSign: (signatureBase64: string) => Promise<void>;
  clientName?: string;
}

export function SignatureModal({ visible, onClose, onSign, clientName }: Props) {
  const sigRef = useRef<SignatureViewRef>(null);
  const [isSaving, setIsSaving] = useState(false);

  // The HTML for the webview that SignatureCanvas uses
  const webStyle = `
    .m-signature-pad { box-shadow: none; border: 2px solid #E4E8EF; border-radius: 12px; }
    .m-signature-pad--body { background-color: #F8FAFC; border-radius: 10px; }
    .m-signature-pad--footer { display: none; }
  `;

  const handleOK = async (signature: string) => {
    setIsSaving(true);
    try {
      await onSign(signature);
      onClose();
    } catch (err) {
      Toast.show({ type: 'error', text1: 'Failed to save signature' });
    } finally {
      setIsSaving(false);
    }
  };

  const handleClear = () => {
    sigRef.current?.clearSignature();
  };

  const handleConfirm = () => {
    sigRef.current?.readSignature();
  };

  return (
    <Modal visible={visible} transparent animationType="slide" onRequestClose={onClose}>
      <View style={s.overlay}>
        <View style={s.sheet}>
          <View style={s.header}>
            <View>
              <Text style={s.title}>Client Sign-off</Text>
              <Text style={s.sub}>Please sign to confirm job completion</Text>
            </View>
            <TouchableOpacity onPress={onClose} style={s.closeBtn}>
              <MaterialCommunityIcons name="close" size={24} color="#8896A8" />
            </TouchableOpacity>
          </View>

          {clientName ? (
            <View style={s.contactBanner}>
              <MaterialCommunityIcons name="account-tie" size={16} color={NAVY} />
              <Text style={s.contactTxt}>Signing as: <Text style={{ fontWeight: '700' }}>{clientName}</Text></Text>
            </View>
          ) : null}

          <View style={s.canvasWrap}>
            <SignatureCanvas
              ref={sigRef}
              onOK={handleOK}
              webStyle={webStyle}
              backgroundColor="#F8FAFC"
              penColor={NAVY}
            />
          </View>

          <View style={s.actions}>
            <TouchableOpacity style={s.clearBtn} onPress={handleClear} disabled={isSaving}>
              <Text style={s.clearTxt}>Clear</Text>
            </TouchableOpacity>
            <TouchableOpacity style={[s.okBtn, isSaving && s.okBtnDisabled]} onPress={handleConfirm} disabled={isSaving}>
              {isSaving ? <ActivityIndicator color={WHITE} size="small" /> : <Text style={s.okTxt}>Save Signature</Text>}
            </TouchableOpacity>
          </View>
        </View>
      </View>
    </Modal>
  );
}

const s = StyleSheet.create({
  overlay: { flex: 1, backgroundColor: 'rgba(0,0,0,0.6)', justifyContent: 'flex-end' },
  sheet:   { backgroundColor: WHITE, borderTopLeftRadius: 24, borderTopRightRadius: 24, padding: 24, paddingBottom: 32 },
  header:  { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 16 },
  title:   { fontSize: 20, fontWeight: '800', color: NAVY },
  sub:     { fontSize: 13, color: '#4B5A6E', marginTop: 2 },
  closeBtn:{ padding: 4, backgroundColor: '#F1F4F8', borderRadius: 20 },
  contactBanner: { flexDirection: 'row', alignItems: 'center', gap: 8, backgroundColor: '#F1F5F9', padding: 12, borderRadius: 8, marginBottom: 16 },
  contactTxt: { fontSize: 13, color: NAVY },
  canvasWrap: { height: 260, marginBottom: 20 },
  actions: { flexDirection: 'row', gap: 12 },
  clearBtn: { flex: 1, alignItems: 'center', justifyContent: 'center', paddingVertical: 16, backgroundColor: '#F1F4F8', borderRadius: 12 },
  clearTxt: { fontSize: 15, fontWeight: '700', color: '#4B5A6E' },
  okBtn:    { flex: 2, alignItems: 'center', justifyContent: 'center', paddingVertical: 16, backgroundColor: SUCCESS, borderRadius: 12 },
  okBtnDisabled: { opacity: 0.7 },
  okTxt:    { fontSize: 15, fontWeight: '700', color: WHITE },
});

import { PropsWithChildren, useState } from 'react';
import { StyleSheet, TouchableOpacity } from 'react-native';

import { ThemedText } from '@/components/themed-text';
import { ThemedView } from '@/components/themed-view';
import { IconSymbol } from '@/components/ui/icon-symbol';
import { Colors } from '@/constants/theme';
import { useColorScheme } from '@/hooks/use-color-scheme';

export function Collapsible({ children, title }: PropsWithChildren & { title: string }) {
  const [isOpen, setIsOpen] = useState(false);
  const theme = useColorScheme() ?? 'light';

  return (
    <ThemedView>
      <TouchableOpacity
        style={styles.heading}
        onPress={() => setIsOpen((value) => !value)}
        activeOpacity={0.8}>
        <IconSymbol
          name="chevron.right"
          size={18}
          weight="medium"
          color={theme === 'light' ? Colors.light.icon : Colors.dark.icon}
          style={{ transform: [{ rotate: isOpen ? '90deg' : '0deg' }] }}
        />

        <ThemedText type="defaultSemiBold">{title}</ThemedText>
      </TouchableOpacity>
      {isOpen && <ThemedView style={styles.content}>{children}</ThemedView>}
    </ThemedView>
  );
}

const styles = StyleSheet.create({
  heading: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 6,
  },
  content: {
    marginTop: 6,
    marginLeft: 24,
  },
});

// Zustand authentication store — manages user session, sign-in/out, and session restoration
import { create } from 'zustand';
import type { Session } from '@supabase/supabase-js';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { supabase, signOut as supabaseSignOut } from '@/lib/supabase';
import { stopSync } from '@/lib/sync';
import { SESSION_KEY } from '@/constants/Config';
import type { User } from '@/types';

const REMEMBER_ME_KEY = '@sitetrack/remember_me';

// ---------------------------------------------
// Types
// ---------------------------------------------

interface AuthState {
  user: User | null;
  session: Session | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  error: string | null;
}

interface AuthActions {
  signIn: (email: string, password: string, rememberMe?: boolean) => Promise<void>;
  signOut: () => Promise<void>;
  restoreSession: () => Promise<void>;
  updateUser: (updates: Partial<User>) => void;
  clearError: () => void;
}

// Helper: race a promise against a timeout — returns null on timeout
function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T | null> {
  const timer = new Promise<null>((resolve) => setTimeout(() => resolve(null), ms));
  return Promise.race([promise, timer]);
}

// ---------------------------------------------
// Store
// ---------------------------------------------

export const useAuthStore = create<AuthState & AuthActions>((set, get) => ({
  user: null,
  session: null,
  isLoading: true,
  isAuthenticated: false,
  error: null,

  // Sign in
  signIn: async (email, password, rememberMe = false) => {
    set({ isLoading: true, error: null });
    try {
      const { data, error } = await supabase.auth.signInWithPassword({
        email: email.trim().toLowerCase(),
        password,
      });

      if (error) {
        set({ error: error.message, isLoading: false });
        return;
      }

      if (!data.session || !data.user) {
        set({ error: 'Sign in failed — no session returned.', isLoading: false });
        return;
      }

      // Fetch full profile from public.users
      const { data: profile, error: profileError } = await supabase
        .from('users')
        .select('*')
        .eq('id', data.user.id)
        .single();

      if (profileError || !profile) {
        set({
          error: 'Account profile not found. Contact your administrator.',
          isLoading: false,
        });
        return;
      }

      if (rememberMe) {
        await AsyncStorage.setItem(REMEMBER_ME_KEY, 'true');
      }

      set({
        user: profile as User,
        session: data.session,
        isAuthenticated: true,
        isLoading: false,
        error: null,
      });
    } catch (err) {
      set({
        error: 'An unexpected error occurred. Please try again.',
        isLoading: false,
      });
    }
  },

  // Sign out
  signOut: async () => {
    set({ isLoading: true });
    try {
      stopSync();
      await supabaseSignOut();
      await AsyncStorage.multiRemove([REMEMBER_ME_KEY, SESSION_KEY]);
    } catch (err) {
      console.error('[AuthStore] signOut error:', err);
    } finally {
      set({
        user: null,
        session: null,
        isAuthenticated: false,
        isLoading: false,
        error: null,
      });
    }
  },

  // Restore session on app launch
  // Uses 5-second timeouts so the app NEVER hangs on the splash screen
  // if Supabase is unreachable (offline, slow network, etc.)
  restoreSession: async () => {
    set({ isLoading: true });
    try {
      // Step 1: get locally-cached session (with safety timeout)
      const sessionResult = await withTimeout(supabase.auth.getSession(), 5000);

      if (!sessionResult || sessionResult.error || !sessionResult.data.session) {
        set({ isLoading: false, isAuthenticated: false });
        return;
      }

      const { session } = sessionResult.data;

      // Step 2: fetch user profile from Supabase (with safety timeout)
      type ProfileResult = { data: User | null; error: { message: string } | null };
      const profileResult = await withTimeout<ProfileResult>(
        (supabase
          .from('users')
          .select('*')
          .eq('id', session.user.id)
          .single() as unknown) as Promise<ProfileResult>,
        5000
      );

      if (!profileResult || profileResult.error || !profileResult.data) {
        // Profile fetch failed / timed out — still let user log in manually
        set({ isLoading: false, isAuthenticated: false });
        return;
      }

      set({
        user: profileResult.data as User,
        session,
        isAuthenticated: true,
        isLoading: false,
        error: null,
      });
    } catch (err) {
      console.error('[AuthStore] restoreSession error:', err);
      set({ isLoading: false, isAuthenticated: false });
    }
  },

  // Update user profile in local state
  updateUser: (updates) => {
    const current = get().user;
    if (current) {
      set({ user: { ...current, ...updates } });
    }
  },

  // Clear error
  clearError: () => set({ error: null }),
}));

// ---------------------------------------------
// Subscribe to Supabase auth state changes
// Handles token refresh, server-side sign-out, etc.
// ---------------------------------------------
supabase.auth.onAuthStateChange((event, session) => {
  if (event === 'SIGNED_OUT' || !session) {
    useAuthStore.setState({
      user: null,
      session: null,
      isAuthenticated: false,
      isLoading: false,
    });
  } else if (event === 'TOKEN_REFRESHED' && session) {
    useAuthStore.setState({ session });
  }
});
